class t{static isString(t){return"string"==typeof t}static isNumber(t){return"number"==typeof t&&!isNaN(t)}static isBoolean(t){return"boolean"==typeof t}static isObject(t){return null!==t&&"object"==typeof t&&!Array.isArray(t)}static isArray(t){return Array.isArray(t)}static isFunction(t){return"function"==typeof t}static isNull(t){return null===t}static isUndefined(t){return void 0===t}static isNullOrUndefined(t){return null==t}static extend(t,...e){return e.forEach(e=>{this.isObject(e)&&Object.keys(e).forEach(r=>{this.isObject(e[r])&&this.isObject(t[r])?t[r]=this.extend({},t[r],e[r]):t[r]=e[r]})}),t}static clone(t){if(this.isNullOrUndefined(t))return t;if(this.isArray(t))return t.map(t=>this.clone(t));if(this.isObject(t)){const e={};return Object.keys(t).forEach(r=>{e[r]=this.clone(t[r])}),e}return t}static unique(t){return[...new Set(t)]}static flatten(t){return t.flat(1/0)}static debounce(t,e){let r;return function(...i){const n=this;clearTimeout(r),r=setTimeout(()=>{clearTimeout(r),t.apply(n,i)},e)}}static throttle(t,e){let r;return function(...i){const n=this;r||(t.apply(n,i),r=!0,setTimeout(()=>r=!1,e))}}static randomId(t="id"){if("undefined"!=typeof crypto&&crypto.getRandomValues){const e=new Uint8Array(8);crypto.getRandomValues(e);return`${t}-${Array.from(e,t=>t.toString(16).padStart(2,"0")).join("")}`}return`${t}-${Math.random().toString(36).substr(2,9)}`}static randomInt(t,e){return Math.floor(Math.random()*(e-t+1))+t}static chunk(t,e){const r=[];for(let i=0;i<t.length;i+=e)r.push(t.slice(i,i+e));return r}static range(t,e,r=1){if(!r||r<=0)return console.error("Utils.range: step은 0보다 커야 합니다."),[];const i=[];for(let n=t;n<=e;n+=r)i.push(n);return i}static truncate(t,e,r="..."){return this.isString(t)?t.length<=e?t:t.substring(0,e-r.length)+r:""}static camelCase(t){return t.replace(/[-_](\w)/g,(t,e)=>e.toUpperCase())}static kebabCase(t){return t.replace(/([a-z])([A-Z])/g,"$1-$2").toLowerCase()}static capitalize(t){return this.isString(t)&&0!==t.length?t.charAt(0).toUpperCase()+t.slice(1):t}static sleep(t){return new Promise(e=>setTimeout(e,t))}static pick(t,e){const r={};return e.forEach(e=>{e in t&&(r[e]=t[e])}),r}static omit(t,e){const r={...t};return e.forEach(t=>{delete r[t]}),r}}export{t as Utils,t as default};
